float get_floor(float x)
{
    int int_part = (int)x;
    float decimal_part = x - int_part;

    // 如果浮点数是负数，并且有小数部分
    if (x < 0.0f && decimal_part != 0.0f)
    {
        return (float)(int_part - 1);  // 向下取整（负数向下取整）
    }
    else
    {
        return (float)int_part;  // 正数直接返回整数部分
    }
}

static inline float tansig_approx(float x)
{
    int i;
    float y, dy;
    float sign = 1.0f;
    /* Tests are reversed to catch NaNs */
    if (!(x < 8.0f))
        return 1.0f;
    if (!(x > -8.0f))
        return -1.0f;
    if (x < 0)
    {
        x = -x;
        sign = -1.0f;
    }
    i = (int)get_floor(.5f + 25.0f * x);
    x -= .04f * i;
    y = tansig_table[i];
    dy = 1.0f - y * y;
    y = y + x * dy * (1.0f - y * x);
    return sign * y;
}

static inline float sigmoid_approx(float x)
{
    return .5f + .5f * tansig_approx(.5f * x);
}

static inline float relu(float x)
{
    return x < 0.0f ? 0.0f : x;
}

#define INPUT_SIZE 42
void compute_vad(const float* input, float* state, float *vad)
{
    int i, j;
    float dense_out[24];
    float temp[24];
    float r[24];
    float h[24];
    float z[24];

    // dense
    for (i = 0; i < 24; i++)
    {
        dense_out[i] = input_dense_bias[i];
        for (j = 0; j < 42; j++)
        {
            dense_out[i] += input_dense_weights[i][j] * input[j];
        }
    }
    for (i = 0; i < 24; i++)
    {
        dense_out[i] = tansig_approx(dense_out[i]);
    }

    // update gate
    for (i = 0; i < 24; i++)
    {
        float sum = vad_gru_bz[i];
        for (j = 0; j < 24; j++)
        {
            sum += vad_gru_Wz[i][j] * dense_out[j];
        }
        for (j = 0; j < 24; j++)
        {
            sum += vad_gru_Uz[i][j] * state[j];
        }
        z[i] = sigmoid_approx(sum);
    }

    // reset gate
    for (i = 0; i < 24; i++)
    {
        float sum = vad_gru_br[i];
        for (j = 0; j < 24; j++)
        {
            sum += vad_gru_Wr[i][j] * dense_out[j];
        }
        for (j = 0; j < 24; j++)
        {
            sum += vad_gru_Ur[i][j] * state[j];
        }
        r[i] = sigmoid_approx(sum);
    }

    // gru output
    for (j = 0; j < 24; j++)
    {
        temp[j] = state[j] * r[j];
    }
    for (i = 0; i < 24; i++)
    {
        float sum = vad_gru_bh[i];
        for (j = 0; j < 24; j++)
        {
            sum += vad_gru_Wh[i][j] * dense_out[j];
        }
        for (j = 0; j < 24; j++)
        {
            sum += vad_gru_Uh[i][j] * temp[j];
        }
        sum = relu(sum);
        h[i] = z[i] * state[i] + (1 - z[i]) * sum;
    }

    for (i = 0; i < 24; i++)
    {
        state[i] = h[i];
    }

    // dense out
    float sum = vad_output_bias[0];
    for (i = 0; i < 24; i++)
    {
        sum += vad_output_weights[0][i] * h[i];
    }
    vad[0] = sigmoid_approx(sum);
}
